/* Base adjustment for body text for better readability */
body {
  font-family: 'Inter', sans-serif;
  letter-spacing: 0.01em; /* Subtle positive spacing for general text */
}

/* Headings often benefit from tighter spacing for a stronger presence */
h1, h2 {
  letter-spacing: -0.025em; /* Negative spacing for large, bold headings */
  font-weight: 700;
}

/* Small text, like captions or navigation, might need more space for clarity */
.small-text, nav a {
  font-size: 0.85em;
  letter-spacing: 0.03em; /* Increased spacing for legibility at small sizes */
}

/* Consider responsive adjustments for different screen sizes */
@media (max-width: 768px) {
  h1 {
    letter-spacing: -0.01em; /* Slightly less aggressive on smaller screens */
  }
}
